import React, { useState } from 'react';

const leaves = (n) => (n.children ? n.children.flatMap(leaves) : [n.id]);

function Node({ node, checked, onToggle }) {
  const ls = leaves(node);
  const on = ls.filter((id) => checked.has(id)).length;
  const state = on === 0 ? 'off' : on === ls.length ? 'on' : 'mixed';

  return (
    <li style={{ listStyle: 'none' }}>
      <label style={{ display: 'flex', alignItems: 'center', gap: 8, padding: '2px 0' }}>
        <input
          type="checkbox"
          checked={state === 'on'}
          ref={(el) => {
            if (el) el.indeterminate = state === 'mixed';
          }}
          onChange={() => onToggle(node)}
        />
        {node.label}
      </label>
      {node.children && (
        <ul style={{ paddingLeft: 22, margin: 0 }}>
          {node.children.map((c) => (
            <Node key={c.id} node={c} checked={checked} onToggle={onToggle} />
          ))}
        </ul>
      )}
    </li>
  );
}

export default function NestedCheckboxes({ tree }) {
  const [checked, setChecked] = useState(() => new Set());

  const toggle = (node) => {
    const ls = leaves(node);
    const allOn = ls.every((id) => checked.has(id));
    const next = new Set(checked);
    ls.forEach((id) => (allOn ? next.delete(id) : next.add(id)));
    setChecked(next);
  };

  return (
    <ul style={{ paddingLeft: 0, margin: 0 }}>
      {tree.map((n) => (
        <Node key={n.id} node={n} checked={checked} onToggle={toggle} />
      ))}
    </ul>
  );
}

vue.answer:
## Building Nested (Tri-state) Checkboxes in Vue 3

**Mental model:** Track only the *leaf* selection (a `Set` of leaf ids). Each parent's state is **derived**: checked if all descendant leaves are selected, unchecked if none, indeterminate otherwise. A recursive component renders the tree; toggling a node flips its whole subtree.

### Step 1 — Leaf-set state + helper
```js
const checked = ref(new Set());
const leaves = (n) => (n.children ? n.children.flatMap(leaves) : [n.id]);
```

### Step 2 — Derive tri-state per node
```js
function stateOf(n) {
  const ls = leaves(n);
  const on = ls.filter((id) => checked.value.has(id)).length;
  return on === 0 ? 'off' : on === ls.length ? 'on' : 'mixed';
}
```

### Step 3 — Toggle a subtree
```js
function toggle(n) {
  const ls = leaves(n);
  const allOn = ls.every((id) => checked.value.has(id));
  const next = new Set(checked.value);
  ls.forEach((id) => (allOn ? next.delete(id) : next.add(id)));
  checked.value = next;
}
```

### Step 4 — Recursive component + indeterminate
A component imports itself; bind `.indeterminate` via a function ref or `:indeterminate` (Vue supports the DOM prop).

```vue
<input type="checkbox" :checked="state === 'on'" :indeterminate="state === 'mixed'" @change="toggle(node)" />
<TreeNode v-for="c in node.children" :key="c.id" :node="c" ... />
```

**Edge cases**

| Case | Handling |
| :-- | :-- |
| Deep nesting | `leaves` recurses; component self-references. |
| Shared state | Pass `checked` + `toggle` down as props. |
| indeterminate | Vue binds it as a DOM property via `:indeterminate`. |

**Interview tip:** Vue lets you bind `:indeterminate` directly (it sets the DOM property), which is cleaner than React's ref dance — and a self-referencing component is the idiomatic way to render arbitrary-depth trees.

angular.answer:
## Building Nested (Tri-state) Checkboxes in Angular

**Mental model:** Track only the *leaf* selection (a `Set` of leaf ids) in a parent component. Each node's state is **derived**: checked if all descendant leaves are selected, none → unchecked, else indeterminate. A self-referencing component renders the tree. Classic `NgModule` setup, no `?.`/`??` (the build rejects them).

### Step 1 — Shared leaf set + helper
The root owns the `Set`; nodes receive it plus a toggle callback.

```typescript
leaves(n: TreeNode): string[] {
  return n.children ? n.children.reduce((a, c) => a.concat(this.leaves(c)), [] as string[]) : [n.id];
}
```

### Step 2 — Derive tri-state
```typescript
stateOf(n: TreeNode): string {
  const ls = this.leaves(n);
  const on = ls.filter((id) => this.checked.has(id)).length;
  return on === 0 ? 'off' : on === ls.length ? 'on' : 'mixed';
}
```

### Step 3 — Toggle a subtree
```typescript
toggle(n: TreeNode): void {
  const ls = this.leaves(n);
  const allOn = ls.every((id) => this.checked.has(id));
  ls.forEach((id) => (allOn ? this.checked.delete(id) : this.checked.add(id)));
}
```

### Step 4 — Recursive template + indeterminate
A component using its own selector renders children; bind `[indeterminate]` (a DOM property) via property binding.

```html
<input type="checkbox" [checked]="stateOf(node) === 'on'" [indeterminate]="stateOf(node) === 'mixed'" (change)="onToggle(node)" />
<app-tree-node *ngFor="let c of node.children" [node]="c" [checked]="checked"></app-tree-node>
```

**Edge cases**

| Case | Handling |
| :-- | :-- |
| Deep nesting | Self-referencing component + recursive `leaves`. |
| Shared state | Pass the same `Set` reference down. |
| indeterminate | `[indeterminate]` binds the DOM property. |

**Interview tip:** Angular binds `[indeterminate]` as a DOM property directly (no ref needed), and a component that uses its own selector in its template is the clean recursion pattern for trees.

