import { Component, Input } from '@angular/core';
import { NgModule } from '@angular/core';
import { BrowserModule } from '@angular/platform-browser';

interface TreeNode { id: string; label: string; children?: TreeNode[]; }

@Component({
  selector: 'app-tree-node',
  template: `
    <li style="list-style: none;">
      <label style="display: flex; align-items: center; gap: 8px; padding: 2px 0;">
        <input
          type="checkbox"
          [checked]="stateOf(node) === 'on'"
          [indeterminate]="stateOf(node) === 'mixed'"
          (change)="toggle(node)"
        />
        {{ node.label }}
      </label>
      <ul *ngIf="node.children" style="padding-left: 22px; margin: 0;">
        <app-tree-node *ngFor="let c of node.children" [node]="c" [checked]="checked"></app-tree-node>
      </ul>
    </li>
  `,
})
export class TreeNodeComponent {
  @Input() node!: TreeNode;
  @Input() checked!: Set<string>;

  leaves(n: TreeNode): string[] {
    return n.children ? n.children.reduce((a, c) => a.concat(this.leaves(c)), [] as string[]) : [n.id];
  }

  stateOf(n: TreeNode): string {
    const ls = this.leaves(n);
    const on = ls.filter((id) => this.checked.has(id)).length;
    return on === 0 ? 'off' : on === ls.length ? 'on' : 'mixed';
  }

  toggle(n: TreeNode): void {
    const ls = this.leaves(n);
    const allOn = ls.every((id) => this.checked.has(id));
    ls.forEach((id) => {
      if (allOn) {
        this.checked.delete(id);
      } else {
        this.checked.add(id);
      }
    });
  }
}

@Component({
  selector: 'app-root',
  template: `
    <div style="font-family: sans-serif; padding: 20px;">
      <h1>Nested Checkboxes Demo</h1>
      <ul style="padding-left: 0; margin: 0;">
        <app-tree-node *ngFor="let n of tree" [node]="n" [checked]="checked"></app-tree-node>
      </ul>
    </div>
  `,
})
export class AppComponent {
  checked = new Set<string>();
  tree: TreeNode[] = [
    {
      id: 'fruit',
      label: 'Fruit',
      children: [
        { id: 'apple', label: 'Apple' },
        { id: 'banana', label: 'Banana' },
        { id: 'cherry', label: 'Cherry' },
      ],
    },
    {
      id: 'veg',
      label: 'Vegetables',
      children: [
        { id: 'carrot', label: 'Carrot' },
        { id: 'pea', label: 'Pea' },
      ],
    },
  ];
}

@NgModule({
  declarations: [AppComponent, TreeNodeComponent],
  imports: [BrowserModule],
  bootstrap: [AppComponent],
})
export class AppModule {}
